(308, 'Xiaomi Router AX3000T', 'Xiaomi Router AX3000T.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'xiaomi router ax3000t', 'xiaomi router ax3000t bộ định tuyến wi-fi 6 giá cả phải chăng mang lại hiệu suất không dây nhanh cho môi trường gia đình và văn phòng. có tốc độ ax3000, kết nối băng tần kép, công nghệ mu-mimo, hỗ trợ mạng lưới, cổng gigabit ethernet, thiết kế nhỏ gọn và giá trị tuyệt vời cho các thiết lập mạng chính thống.'),
(309, 'Netgear Nighthawk AX12 RAX120', 'Netgear Nighthawk AX12 RAX120.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'netgear nighthawk ax12 rax120', 'netgear nighthawk ax12 rax120 bộ định tuyến wi-fi 6 cao cấp được thiết kế cho những ngôi nhà lớn, chơi game và khối lượng công việc phát trực tuyến nặng. có hiệu suất không dây ax6000, bộ xử lý lõi tứ mạnh mẽ, nhiều cổng gigabit, định dạng chùm tia tiên tiến, kết nối usb 3.0 và khả năng xử lý thiết bị mở rộng cho các mạng đòi hỏi khắt khe.'),
(310, 'TP-Link Archer C6', 'TP-Link Archer C6.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'tp link archer c6', 'tp-link archer c6 một trong những bộ định tuyến ngân sách được mua phổ biến nhất trên toàn thế giới. có tốc độ không dây ac1200 băng tần kép, hỗ trợ mu-mimo, bốn ăng-ten bên ngoài, chế độ điểm truy cập, cổng gigabit và hiệu suất không dây ổn định phù hợp cho việc sử dụng internet gia đình và thiết lập văn phòng.'),
(311, 'ASUS RT-AX86U Pro', 'ASUS RT-AX86U Pro.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'asus rt ax86u pro', 'asus rt-ax86u pro bộ định tuyến chơi game cao cấp được thiết kế cho thể thao điện tử, phát trực tuyến và hiệu suất internet tốc độ cao. có tốc độ wi-fi 6 ax5700, chế độ chơi game di động, điều khiển qos nâng cao, bộ bảo mật aiprotection, cổng 2.5g kép, tối ưu hóa độ trễ thấp và khả năng tương thích aimesh để mở rộng phạm vi phủ sóng.'),
(312, 'Huawei AX3 Quad-Core', 'Huawei AX3 Quad-Core.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'huawei ax3 quad core', 'huawei ax3 quad-core bộ định tuyến wi-fi 6 nhỏ gọn có kiến trúc bộ xử lý lõi tứ, kết nối không dây băng tần kép, hỗ trợ harmonyos mesh+, ghép nối một chạm nfc, cổng gigabit và tối ưu hóa tín hiệu không dây mạnh mẽ cho gia đình và căn hộ.'),
(313, 'Lmucsys MR7350', 'Lmucsys MR7350.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'lmucsys mr7350', 'lmucsys mr7350 bộ định tuyến băng tần kép wi-fi 6 đáng tin cậy được thiết kế để kết nối mạng gia đình và thiết bị thông minh. có tốc độ không dây ax1800, hỗ trợ mở rộng lưới, qos thông minh, kiểm soát của phụ huynh, cổng gigabit ethernet và hiệu suất đa thiết bị ổn định cho các hộ gia đình hiện đại.'),
(314, 'Corsair RM750x', 'Corsair RM750x.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'corsair rm750x', 'corsair rm750x bộ nguồn mô-đun hoàn toàn 750w cao cấp được thiết kế cho máy tính chơi game và máy trạm chuyên nghiệp. có chứng nhận hiệu quả 80 plus gold, thiết kế cáp mô-đun hoàn toàn, quạt 135mm có độ ồn cực thấp, tụ điện nhật bản, chế độ quạt zero rpm, khả năng tương thích atx và cung cấp năng lượng đáng tin cậy cho các hệ thống chơi game hiệu suất cao.'),
(315, 'Cooler Master MWE Gold 750 V2', 'Cooler Master MWE Gold 750 V2.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'cooler master mwe gold 750 v2', 'cooler master mwe gold 750 v2 bộ nguồn chơi game được sử dụng rộng rãi cung cấp công suất 750w, chứng nhận 80 plus gold, chuyển đổi nguồn dc-to-dc, quạt làm mát yên tĩnh, cáp mô-đun hoàn toàn và hiệu quả ổn định cho pc chơi game và năng suất. thích hợp cho các hệ thống card đồ họa nvidia và amd hiện đại.'),
(316, 'ASUS ROG Strix 850G', 'ASUS ROG Strix 850G.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'asus rog strix 850g', 'asus rog strix 850g psu chơi game cao cấp được thiết kế cho các bản dựng pc đam mê. có công suất 850w, hiệu suất 80 plus gold, cáp mô-đun hoàn toàn, tản nhiệt cao cấp, quạt làm mát công nghệ hướng trục, tụ điện nhật bản và hoạt động ít tiếng ồn được tối ưu hóa cho các hệ thống chơi game và sáng tạo.'),
(317, 'MSI MAG A650BN', 'MSI MAG A650BN.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'msi mag a650bn', 'msi mag a650bn bộ nguồn thân thiện với ngân sách phổ biến được thiết kế cho các hệ thống máy tính để bàn văn phòng và chơi game chính thống. có công suất 650w, chứng nhận 80 plus bronze, thiết kế pfc chủ động, quạt làm mát yên tĩnh, điều chỉnh điện áp ổn định và hiệu suất đáng tin cậy cho các bản dựng pc cấp thấp và tầm trung.'),
(318, 'Seasonic Focus GX-750', 'Seasonic Focus GX-750.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'seasonic focus gx 750', 'seasonic focus gx-750 psu cao cấp được đánh giá cao trên toàn cầu với công suất 750w, chứng nhận 80 plus gold, cáp mô-đun hoàn toàn, điều khiển quạt im lặng lai, thiết kế atx nhỏ gọn và độ tin cậy lâu dài vượt trội cho máy tính chơi game và máy trạm.'),
(319, 'Corsair CV650', 'Corsair CV650.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'corsair cv650', 'corsair cv650 bộ nguồn máy tính để bàn giá cả phải chăng và đáng tin cậy được thiết kế cho các hệ thống văn phòng và pc chơi game cấp thấp. có công suất 650w, hiệu suất 80 plus bronze, quạt làm mát tiếng ồn thấp 120mm, cung cấp năng lượng liên tục và khả năng tương thích với các thành phần máy tính để bàn hiện đại.'),
(320, 'Gigabyte UD750GM', 'Gigabyte UD750GM.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'gigabyte ud750gm', 'gigabyte ud750gm bộ nguồn chơi game hoàn toàn theo mô-đun có công suất 750w, hiệu suất 80 plus gold, tụ điện nhật bản chất lượng cao, quạt ổ trục thủy lực thông minh, thiết kế nhỏ gọn và đầu ra hiệu suất cao ổn định cho hệ thống chơi game và phát trực tuyến.'),
(321, 'Thermaltake Toughpower GF A3 850W', 'Thermaltake Toughpower GF A3 850W.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'thermaltake toughpower gf a3 850w', 'thermaltake toughpower gf a3 850w bộ nguồn tương thích atx 3.0 hiện đại được thiết kế cho phần cứng chơi game thế hệ tiếp theo. có công suất 850w, hiệu suất 80 plus gold, hỗ trợ pcie gen 5, thiết kế mô-đun hoàn toàn, hệ thống làm mát cực kỳ yên tĩnh và khả năng tương thích mạnh mẽ với card đồ họa rtx 40-series.'),
(322, 'DeepCool PK650D', 'DeepCool PK650D.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'deepcool pk650d', 'deepcool pk650d psu định hướng ngân sách đáng tin cậy cung cấp công suất 650w, hiệu suất 80 plus bronze, các thành phần bên trong bền, pfc hoạt động, điều chỉnh điện áp ổn định và hiệu suất quạt yên tĩnh cho hệ thống máy tính để bàn văn phòng và chơi game.'),
(323, 'EVGA SuperNOVA 850 G6', 'EVGA SuperNOVA 850 G6.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'evga supernova 850 g6', 'evga supernova 850 g6 psu mô-đun hoàn toàn đẳng cấp dành cho người đam mê có công suất đầu ra 850w, chứng nhận 80 plus gold, quạt hoạt động im lặng ở chế độ sinh thái, thiết kế nhỏ gọn, tụ điện cao cấp của nhật bản và hiệu quả cao cho máy trạm chơi game và máy tính để bàn cao cấp.'),
(324, 'Logitech G Pro X TKL Lightspeed', 'Logitech G Pro X TKL Lightspeed.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'logitech g pro x tkl lightspeed', 'logitech g pro x tkl lightspeed bàn phím chơi game thể thao điện tử chuyên nghiệp được thiết kế cho các game thủ và streamer cạnh tranh. có kết nối lightspeed không dây, bố cục không cần phím, ánh sáng rgb lightsync có thể tùy chỉnh, phím có thể lập trình, cấu hình bộ nhớ tích hợp, công tắc gx cơ học, điều khiển phương tiện và hiệu suất độ trễ cực thấp được tối ưu hóa cho chơi game thể thao điện tử.'),
(325, 'Razer Huntsman V2', 'Razer Huntsman V2.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'razer huntsman v2', 'razer huntsman v2 bàn phím chơi game cao cấp có công tắc quang razer để kích hoạt cực nhanh và độ trễ thấp. bao gồm keycaps pbt doubleshot, đèn rgb chroma, bọt giảm âm, tựa cổ tay từ tính, điều khiển phương tiện chuyên dụng và thăm dò usb tốc độ cao cho hiệu suất chơi game cạnh tranh.'),
(326, 'Corsair K100 RGB', 'Corsair K100 RGB.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'corsair k100 rgb', 'corsair k100 rgb bàn phím chơi game cao cấp được thiết kế cho những người đam mê và game thủ chuyên nghiệp. có công tắc cơ quang corsair opx, đèn rgb trên mỗi phím, điều khiển macro chuyên dụng, cấu trúc khung nhôm, công nghệ siêu thăm dò 8000hz, tựa cổ tay có thể tháo rời và bánh xe điều khiển đa chức năng.'),
(327, 'Logitech MX Keys S', 'Logitech MX Keys S.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'logitech mx keys s', 'logitech mx keys s bàn phím văn phòng cao cấp được sử dụng rộng rãi được thiết kế cho năng suất và quy trình làm việc chuyên nghiệp. có công tắc cắt kéo cấu hình thấp, đèn nền thông minh, kết nối bluetooth đa thiết bị, sạc usb-c, trải nghiệm gõ yên tĩnh, thiết kế tiện dụng và khả năng tương thích với hệ thống windows và macos.'),
(328, 'Keychron K2 Wireless Mechanical Keyboard', 'Keychron K2 Wireless Mechanical Keyboard.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'keychron k2 wireless mechanical keyboard', 'keychron k2 wireless mechanical keyboard bàn phím cơ không dây phổ biến được sử dụng rộng rãi cho công việc văn phòng và chơi game thông thường. có bố cục 75% nhỏ gọn, kết nối bluetooth và có dây, tùy chọn công tắc có thể thay thế nóng, đèn nền rgb, khả năng tương thích macos và windows và thời lượng pin dài.'),
(329, 'SteelSeries Apex Pro TKL', 'SteelSeries Apex Pro TKL.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'steelseries apex pro tkl', 'steelseries apex pro tkl bàn phím chơi game tiên tiến có công tắc cơ học có thể điều chỉnh omnipoint cho các điểm kích hoạt có thể tùy chỉnh. bao gồm màn hình thông minh oled, đèn rgb, khung nhôm cấp máy bay, truyền qua usb, phần tựa cổ tay có thể tháo rời và thiết kế không phím mười phím sẵn sàng cho giải đấu.'),
(330, 'ASUS ROG Azoth', 'ASUS ROG Azoth.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'asus rog azoth', 'asus rog azoth bàn phím chơi game kiểu tùy chỉnh cao cấp có màn hình oled, thiết kế gắn miếng đệm, công tắc có thể thay thế nóng, kết nối ba chế độ, ánh sáng rgb, âm thanh gõ cao cấp, các lớp giảm chấn silicone và tùy chỉnh cấp độ người đam mê để chơi game và năng suất.'),
(331, 'Dell KB216 Multimedia Keyboard', 'Dell KB216 Multimedia Keyboard.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'dell kb216 multimedia keyboard', 'dell kb216 multimedia keyboard bàn phím văn phòng đáng tin cậy được sử dụng rộng rãi trong các doanh nghiệp, trường học và môi trường văn phòng trên toàn thế giới. có bố cục kích thước đầy đủ, phím tắt đa phương tiện, kết nối usb, trải nghiệm gõ êm ái, công tắc màng bền và thiết kế năng suất hàng ngày tiện dụng.');

